-- Madar Store phase 1: schema, RBAC, RLS and Storage.
create extension if not exists pgcrypto;
create type public.app_role as enum ('SUPER_ADMIN','ADMIN','EDITOR','CUSTOMER');
create type public.account_status as enum ('active','disabled');
create type public.catalog_status as enum ('draft','published','archived');
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade,email text not null,full_name text,phone text,avatar_url text,role public.app_role not null default 'CUSTOMER',status public.account_status not null default 'active',email_verified boolean not null default false,last_login_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.categories (id uuid primary key default gen_random_uuid(),name text not null,slug text not null unique,description text,image_url text,is_active boolean not null default true,sort_order integer not null default 0,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.products (id uuid primary key default gen_random_uuid(),name text not null,slug text not null unique,short_description text,long_description text,price numeric(12,2) not null check(price>=0),compare_at_price numeric(12,2) check(compare_at_price is null or compare_at_price>=0),currency text not null default 'SAR',category_id uuid references public.categories(id) on delete restrict,status public.catalog_status not null default 'draft',is_featured boolean not null default false,thumbnail_url text,delivery_type text not null default 'digital',features jsonb not null default '[]',includes jsonb not null default '[]',seo_title text,seo_description text,published_at timestamptz,created_by uuid references public.profiles(id) on delete set null,updated_by uuid references public.profiles(id) on delete set null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.product_images (id uuid primary key default gen_random_uuid(),product_id uuid not null references public.products(id) on delete cascade,storage_path text not null unique,alt_text text,sort_order integer not null default 0,created_at timestamptz not null default now());
create table public.product_files (id uuid primary key default gen_random_uuid(),product_id uuid not null references public.products(id) on delete cascade,storage_path text not null unique,original_filename text not null,mime_type text not null,file_size bigint not null check(file_size>=0),version integer not null default 1,is_active boolean not null default true,created_by uuid references public.profiles(id) on delete set null,created_at timestamptz not null default now());
create table public.services (id uuid primary key default gen_random_uuid(),name text not null,slug text not null unique,short_description text,long_description text,price_from numeric(12,2) not null check(price_from>=0),currency text not null default 'SAR',status public.catalog_status not null default 'draft',is_featured boolean not null default false,thumbnail_url text,features jsonb not null default '[]',seo_title text,seo_description text,published_at timestamptz,created_by uuid references public.profiles(id) on delete set null,updated_by uuid references public.profiles(id) on delete set null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.service_images (id uuid primary key default gen_random_uuid(),service_id uuid not null references public.services(id) on delete cascade,storage_path text not null unique,alt_text text,sort_order integer not null default 0,created_at timestamptz not null default now());
create table public.audit_logs (id uuid primary key default gen_random_uuid(),actor_id uuid references public.profiles(id) on delete set null,action text not null,entity_type text not null,entity_id uuid,metadata jsonb not null default '{}',ip_address inet,created_at timestamptz not null default now());
create index products_status_category_published_idx on public.products(status,category_id,published_at desc); create index services_status_published_idx on public.services(status,published_at desc); create index audit_logs_created_idx on public.audit_logs(created_at desc); create index profiles_role_status_idx on public.profiles(role,status);
create or replace function public.touch_updated_at() returns trigger language plpgsql security invoker set search_path=public as $$ begin new.updated_at=now(); return new; end; $$;
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.profiles(id,email,full_name,email_verified) values(new.id,new.email,coalesce(new.raw_user_meta_data->>'full_name',''),new.email_confirmed_at is not null) on conflict(id) do update set email=excluded.email,email_verified=excluded.email_verified; return new; end; $$;
create trigger profiles_updated before update on public.profiles for each row execute function public.touch_updated_at(); create trigger categories_updated before update on public.categories for each row execute function public.touch_updated_at(); create trigger products_updated before update on public.products for each row execute function public.touch_updated_at(); create trigger services_updated before update on public.services for each row execute function public.touch_updated_at(); create trigger on_auth_user_created after insert or update of email,email_confirmed_at on auth.users for each row execute function public.handle_new_user();
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from public.profiles where id=auth.uid() and status='active' and role in ('ADMIN','SUPER_ADMIN')); $$;
create or replace function public.is_super_admin() returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from public.profiles where id=auth.uid() and status='active' and role='SUPER_ADMIN'); $$;
alter table public.profiles enable row level security; alter table public.categories enable row level security; alter table public.products enable row level security; alter table public.product_images enable row level security; alter table public.product_files enable row level security; alter table public.services enable row level security; alter table public.service_images enable row level security; alter table public.audit_logs enable row level security;
create policy "profile self read" on public.profiles for select using(auth.uid()=id); create policy "profile self update safe" on public.profiles for update using(auth.uid()=id) with check(auth.uid()=id and role=(select role from public.profiles where id=auth.uid()) and status=(select status from public.profiles where id=auth.uid())); create policy "super admin profiles" on public.profiles for all using(public.is_super_admin()) with check(public.is_super_admin());
create policy "active categories public" on public.categories for select using(is_active or public.is_admin()); create policy "admins categories" on public.categories for all using(public.is_admin()) with check(public.is_admin());
create policy "published products public" on public.products for select using(status='published' or public.is_admin()); create policy "admins products" on public.products for all using(public.is_admin()) with check(public.is_admin());
create policy "published product images public" on public.product_images for select using(exists(select 1 from public.products p where p.id=product_id and (p.status='published' or public.is_admin()))); create policy "admins product images" on public.product_images for all using(public.is_admin()) with check(public.is_admin()); create policy "admins product files" on public.product_files for all using(public.is_admin()) with check(public.is_admin());
create policy "published services public" on public.services for select using(status='published' or public.is_admin()); create policy "admins services" on public.services for all using(public.is_admin()) with check(public.is_admin()); create policy "published service images public" on public.service_images for select using(exists(select 1 from public.services s where s.id=service_id and (s.status='published' or public.is_admin()))); create policy "admins service images" on public.service_images for all using(public.is_admin()) with check(public.is_admin()); create policy "admins audit" on public.audit_logs for select using(public.is_admin()); create policy "admins audit writes" on public.audit_logs for insert with check(public.is_admin());
insert into storage.buckets(id,name,public) values('catalog-images','catalog-images',true),('digital-products','digital-products',false),('avatars','avatars',false) on conflict(id) do update set public=excluded.public;
create policy "catalog public read" on storage.objects for select using(bucket_id='catalog-images'); create policy "catalog admin write" on storage.objects for all using(bucket_id='catalog-images' and public.is_admin()) with check(bucket_id='catalog-images' and public.is_admin()); create policy "avatar owner" on storage.objects for all using(bucket_id='avatars' and (storage.foldername(name))[1]=auth.uid()::text) with check(bucket_id='avatars' and (storage.foldername(name))[1]=auth.uid()::text); create policy "digital admin only" on storage.objects for all using(bucket_id='digital-products' and public.is_admin()) with check(bucket_id='digital-products' and public.is_admin());
